export default function SignUpPage() {
  const navigate = useNavigate();

  // null = closed; "terms" or "privacy" = which content to show
  const [activeModal, setActiveModal] = useState(null);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting, isValid },
  } = useForm({
    // resolver: zodResolver(signUpSchema),
    mode: "onChange",
    defaultValues: {
      email: "",
      password: "",
      confirmPassword: "",
    },
  });

  const onSubmit = async (data) => {
    try {
      console.log("Validated Sign Up Data:", data);
      // await api.signUp(data);
      navigate("/sign-up/otp");
    } catch (error) {
      console.error("Sign up failed:", error);
    }
  };

  const active = activeModal ? LEGAL_CONTENT[activeModal] : null;

  return (
    <div className="md:relative space-y-[2em] flex flex-col justify-center md:min-h-[calc(100vh-80px)] ">

      <div className="space-y-[2em]">
        <div>
          <h1 className="auth-heading">Sign Up</h1>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="mt-6 space-y-[2.5em]">
          <AuthInput
            label="Email Address"
            type="email"
            placeholder="Enter your email address"
            icon="iconoir:mail"
            error={errors.email?.message}
            {...register("email")}
          />

          <AuthInput
            label="Password"
            type="password"
            placeholder="Enter your password"
            icon="solar:lock-password-linear"
            showToggle
            error={errors.password?.message}
            {...register("password")}
          />

          <AuthInput
            label="Confirm Password"
            type="password"
            placeholder="Enter your confirm password"
            icon="solar:lock-password-linear"
            showToggle
            error={errors.confirmPassword?.message}
            {...register("confirmPassword")}
          />

          <div className="flex auth-options -mt-[1em] mb-[3em] items-center justify-center gap-[1em]">
            <button
              type="button"
              onClick={() => setActiveModal("terms")}
              className="font-medium text-brand transition hover:text-brand-dark"
            >
              Terms of Service
            </button>

            <span>|</span>

            <button
              type="button"
              onClick={() => setActiveModal("privacy")}
              className="font-medium text-brand transition hover:text-brand-dark"
            >
              Privacy Policy
            </button>
          </div>

          <AuthButton type="submit" className="w-full" disabled={isSubmitting || !isValid}>
            {isSubmitting ? "Signing up..." : "Sign Up"}
          </AuthButton>
        </form>

        <ContentModal
          heading={active?.heading}
          content={active?.content}
          isOpen={activeModal !== null}
          onClose={() => setActiveModal(null)}
        />
      </div>

      <div className="flex justify-center md:absolute md:left-1/2 md:-translate-x-1/2 md:bottom-5">
        <span className="auth-sub-heading ">
          Already have an account? <Link className="text-brand" to={"/sign-up"}>Sign In</Link>
        </span>
      </div>
    </div>
  );
}